class Solution {
public:
    vector<vector<string>> findDuplicate(vector<string>& paths) {
        unordered_map<string, vector<string>> fileMap;
        for (string path : paths) {
            string dir = path.substr(0, path.find(" "));
            vector<string> files = split(path.substr(path.find(" ") + 1));
            for (string file : files) {
                string content = file.substr(file.find("(") + 1, file.find(")") - file.find("(") - 1);
                fileMap[content].push_back(dir + "/" + file.substr(0, file.find(".")));
            }
        }
        vector<vector<string>> result;
        for (auto it : fileMap) {
            if (it.second.size() > 1) {
                result.push_back(it.second);
            }
        }
        return result;
    }
    vector<string> split(string str) {
        vector<string> result;
        string current = "";
        for (char c : str) {
            if (c == ' ') {
                result.push_back(current);
                current = "";
            } else {
                current += c;
            }
        }
        result.push_back(current);
        return result;
    }
};
